select
id, server_resources_id, fail_reason, is_deleted, create_user, update_user, create_time, update_time, status
from failed_domain_blocking_log

    1 = 1 and is_deleted = 0

        and id = #{id}


        and server_resources_id = #{serverResourcesId}


        and fail_reason = #{failReason}


        and is_deleted = #{isDeleted}


        and create_user = #{createUser}


        and update_user = #{updateUser}


        and create_time = #{createTime}


        and update_time = #{updateTime}


        and status = #{status}

